[Console]::OutputEncoding = [Text.Encoding]::UTF8
Write-Host ""
Write-Host "  ============================================" -ForegroundColor Cyan
Write-Host "     小智造物 - Arduino AI 学习平台" -ForegroundColor Cyan
Write-Host "     一键安装程序" -ForegroundColor Cyan
Write-Host "  ============================================" -ForegroundColor Cyan
Write-Host ""

$Target = Join-Path $env:LOCALAPPDATA "小智造物"
Write-Host "  安装目录: $Target"

Write-Host ""
Write-Host "  [1/5] 创建程序目录..." -ForegroundColor Yellow
New-Item -ItemType Directory -Path $Target -Force | Out-Null
New-Item -ItemType Directory -Path (Join-Path $Target "data") -Force | Out-Null
Write-Host "    OK" -ForegroundColor Green

Write-Host "  [2/5] 释放程序文件..." -ForegroundColor Yellow
Write-Host "    main.py..." -NoNewline
$b64 = ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$bytes = [Convert]::FromBase64String($b64)
[IO.File]::WriteAllBytes((Join-Path $Target "main.py"), $bytes)
Write-Host " OK" -ForegroundColor Green
Write-Host "    index.html..." -NoNewline
$b64 = ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$bytes = [Convert]::FromBase64String($b64)
[IO.File]::WriteAllBytes((Join-Path $Target "index.html"), $bytes)
Write-Host " OK" -ForegroundColor Green
Write-Host "    config.json..." -NoNewline
$b64 = ""
$b64 += ""
$b64 += ""
$b64 += ""
$bytes = [Convert]::FromBase64String($b64)
[IO.File]::WriteAllBytes((Join-Path $Target "config.json"), $bytes)
Write-Host " OK" -ForegroundColor Green
Write-Host "    start.bat..." -NoNewline
$b64 = ""
$b64 += ""
$bytes = [Convert]::FromBase64String($b64)
[IO.File]::WriteAllBytes((Join-Path $Target "start.bat"), $bytes)
Write-Host " OK" -ForegroundColor Green

Write-Host "  [3/5] 检测 Python 环境..." -ForegroundColor Yellow
python --version 2>&1 | Out-Null
if ($LASTEXITCODE -ne 0) {
    Write-Host "    Python 未安装，正在自动安装..." -ForegroundColor Red
    Write-Host "    [如弹出安装窗口，请按默认选项下一步]"
    try {
        winget install Python.Python.3.10 --silent --accept-source-agreements --accept-package-agreements 2>&1 | Out-Null
    } catch {
        Write-Host "    winget不可用，从官网下载..."
        $pyUrl = "https://www.python.org/ftp/python/3.10.11/python-3.10.11-amd64.exe"
        $pyFile = Join-Path $env:TEMP "pyinst.exe"
        Invoke-WebRequest -Uri $pyUrl -OutFile $pyFile
        Start-Process $pyFile -ArgumentList "/quiet InstallAllUsers=0 PrependPath=1 Include_test=0" -Wait
    }
    $pyDir = Join-Path $env:LOCALAPPDATA "Programs\Python\Python310"
    $pyScripts = Join-Path $env:LOCALAPPDATA "Programs\Python\Python310\Scripts"
    $env:PATH = "$pyDir;$pyScripts;$env:PATH"
    python --version 2>&1 | Out-Null
    if ($LASTEXITCODE -ne 0) {
        Write-Host "    Python 安装失败！请手动安装" -ForegroundColor Red
        Write-Host "    https://www.python.org/downloads/" -ForegroundColor Yellow
        Read-Host "    按回车退出"
        exit 1
    }
}
$ver = python --version 2>&1
Write-Host "    $ver" -ForegroundColor Green

Write-Host "  [4/5] 安装串口通信库..." -ForegroundColor Yellow
python -c "import serial" 2>&1 | Out-Null
if ($LASTEXITCODE -ne 0) {
    pip install pyserial -q 2>&1 | Out-Null
    Write-Host "    pyserial 已安装" -ForegroundColor Green
} else {
    Write-Host "    pyserial 已就绪" -ForegroundColor Green
}

Write-Host "  [5/5] 检测 Arduino 编译环境..." -ForegroundColor Yellow
$hasCli = Get-Command arduino-cli -ErrorAction SilentlyContinue
if (-not $hasCli) {
    Write-Host "    正在下载 Arduino 编译器（约20MB）..."
    $toolsDir = Join-Path $Target "tools"
    New-Item -ItemType Directory -Path $toolsDir -Force | Out-Null
    $zipFile = Join-Path $env:TEMP "arduino-cli.zip"
    Invoke-WebRequest -Uri "https://downloads.arduino.cc/arduino-cli/arduino-cli_latest_Windows_64bit.zip" -OutFile $zipFile
    Expand-Archive -Path $zipFile -DestinationPath $toolsDir -Force
    Remove-Item $zipFile -Force -ErrorAction SilentlyContinue
    $env:PATH = "$toolsDir;$env:PATH"
}
$hasCore = arduino-cli core list 2>&1 | Select-String "arduino:avr"
if (-not $hasCore) {
    Write-Host "    正在安装 Arduino AVR 核心（约100MB，需1-2分钟）..."
    arduino-cli core update-index 2>&1 | Out-Null
    arduino-cli core install arduino:avr 2>&1 | Out-Null
}
Write-Host "    Arduino 编译环境已就绪" -ForegroundColor Green

Write-Host ""
$lnk = Join-Path $env:USERPROFILE "Desktop\小智造物.lnk"
$sh = New-Object -COM WScript.Shell
$sc = $sh.CreateShortcut($lnk)
$sc.TargetPath = Join-Path $Target "start.bat"
$sc.WorkingDirectory = $Target
$sc.Description = "小智造物 - Arduino AI 学习平台"
$sc.Save()
Write-Host "  桌面快捷方式已创建" -ForegroundColor Green

Write-Host ""
Write-Host "  ============================================" -ForegroundColor Cyan
Write-Host "   安装完成！" -ForegroundColor Green
Write-Host "  ============================================" -ForegroundColor Cyan
Write-Host ""
Write-Host "  使用方法："
Write-Host "    1. 用USB线连接Arduino到电脑"
Write-Host "    2. 双击桌面 小智造物 快捷方式"
Write-Host "    3. 开始和小智聊天吧！"
Write-Host ""

$launch = Read-Host "  现在就启动吗？(Y/N)"
if ($launch -eq "Y" -or $launch -eq "y") {
    Start-Process (Join-Path $Target "start.bat")
}

Read-Host "  按回车退出"